module counter5bit_inc3 (
    input clk,
    input rst,
    input en,
    output [4:0] q
);

    reg [4:0] count_reg;

    always @(posedge clk or posedge rst) begin
        if (rst)
            count_reg <= 5'b0;
        else if (en)
            count_reg <= count_reg + 3;
    end

    assign q = count_reg;

endmodule
